  *
  * @param gen  a call-by-name Chisel module
  * @param args additional command line arguments to pass to Chisel
  */
def emitCHIRRTLFile(
  gen:  => RawModule,
  args: Array[String] = Array.empty
): AnnotationSeq = {
  (new circt.stage.ChiselStage).execute(
    Array("--target", "chirrtl") ++ args,
